+                    break;
+                }
+            }
+        }
+
+        last_quadrant = quadrant;
+    }
+
+    int v = (quad_acc >= 2) || (quad_acc <= -2);
+
+    if (0 && v != g2d_polygon_contains_point_ref(poly, q)) {
+        printf("FAILURE %d %d\n", v, quad_acc);
+        exit(-1);
+    }
