+matd_t *matd_create(int rows, int cols)
+{
+    assert(rows >= 0);
+    assert(cols >= 0);
+
+    if (rows == 0 || cols == 0)
+        return matd_create_scalar(0);
+
+    matd_t *m = calloc(1, sizeof(matd_t) + (rows*cols*sizeof(double)));
+    m->nrows = rows;
+    m->ncols = cols;
+
+    return m;
