+
+matd_t *matd_create_dataf(int rows, int cols, const float *data)
+{
+    if (rows == 0 || cols == 0)
+        return matd_create_scalar(data[0]);
+
+    matd_t *m = matd_create(rows, cols);
+    for (int i = 0; i < rows * cols; i++)
