+
+// row and col are zero-based
+TYPE matd_get(const matd_t *m, int row, int col)
+{
+    assert(m != NULL);
+    assert(!matd_is_scalar(m));
+    assert(row >= 0);
+    assert(row < m->nrows);
+    assert(col >= 0);
+    assert(col < m->ncols);
