+matd_t *matd_multiply(const matd_t *a, const matd_t *b)
+{
+    assert(a != NULL);
+    assert(b != NULL);
+
+    if (matd_is_scalar(a))
+        return matd_scale(b, a->data[0]);
+    if (matd_is_scalar(b))
+        return matd_scale(a, b->data[0]);
