+    if (matd_is_scalar(a))
+        return matd_create_scalar(a->data[0] * s);
+
+    matd_t *m = matd_create(a->nrows, a->ncols);
+
+    for (int i = 0; i < m->nrows; i++) {
+        for (int j = 0; j < m->ncols; j++) {
+            MATD_EL(m, i, j) = s * MATD_EL(a, i, j);
