+    if (matd_is_scalar(a))
+        return matd_create_scalar(a->data[0] - b->data[0]);
+
+    matd_t *m = matd_create(a->nrows, a->ncols);
+
+    for (int i = 0; i < m->nrows; i++) {
+        for (int j = 0; j < m->ncols; j++) {
+            MATD_EL(m, i, j) = MATD_EL(a, i, j) - MATD_EL(b, i, j);
