+
+void matd_subtract_inplace(matd_t *a, const matd_t *b)
+{
+    assert(a != NULL);
+    assert(b != NULL);
+    assert(a->nrows == b->nrows);
+    assert(a->ncols == b->ncols);
+
+    if (matd_is_scalar(a)) {
+        a->data[0] -= b->data[0];
+        return;
