+// Solve: (U')x = b, U is upper triangular
+void matd_ltransposetriangle_solve(matd_t *u, const TYPE *b, TYPE *x)
+{
+    int n = u->ncols;
+    memcpy(x, b, n*sizeof(TYPE));
+    for (int i = 0; i < n; i++) {
+        x[i] /= MATD_EL(u, i, i);
+
+        for (int j = i+1; j < u->ncols; j++) {
+            x[j] -= x[i] * MATD_EL(u, i, j);
+        }
+    }
+}
