+uint32_t zhash_ptr_hash(const void *a)
+{
+    assert(a != NULL);
+
+    union uintpointer ip;
+    ip.p = * (void**)a;
+
+    // compute a hash from the lower 32 bits of the pointer (on LE systems)
+    uint32_t hash = ip.i;
+    hash ^= (hash >> 7);
+
+    return hash;
